What does this program print?

```cpp
#include <iostream>

namespace Outer {
    inline namespace Inner {
        int value = 10;
    }
}

int main() {
    std::cout << Outer::value << "\n";
    std::cout << Outer::Inner::value << "\n";
    return 0;
}
```

A developer put a shared counter in an unnamed namespace in a header to make it reachable from multiple `.cpp` files. What is wrong?

```cpp
// counter.h
#pragma once
namespace {
    int sharedCount = 0;
}

void increment() { ++sharedCount; }
int getCount()   { return sharedCount; }
```

What does this program print?

```cpp
#include <iostream>

namespace Lib {
    namespace v1 { int compute(int x) { return x + 1; } }
    inline namespace v2 { int compute(int x) { return x * 2; } }
}

int main() {
    std::cout << Lib::compute(5) << "\n";
    std::cout << Lib::v1::compute(5) << "\n";
    return 0;
}
```
